rule.example:
class Something
{
    private int _unused = 5; // never read
    private int _used = 6;
    public int AddOne() { return _used++; }
}

class Foo
{
    public void DoSomething()
    {
        int unused = 5; // never read
    }
}

class Something
{
    private void Dead() {} // never called
}

class Foo
{
    private void Bar(int howdy)
    {
        // howdy is not used
    }
}
